const esc=v=>{const s=String(v??'');return s.includes(',')||s.includes('"')?`"${s.replace(/"/g,'""')}"`:s;};
const pLine=line=>{const r=[];let cur='',inQ=false;for(let i=0;i<line.length;i++){const c=line[i];if(c==='"'){if(inQ&&line[i+1]==='"'){cur+='"';i++;}else inQ=!inQ;}else if(c===','&&!inQ){r.push(cur);cur='';}else cur+=c;}r.push(cur);return r;};
const genCSV=client=>{let csv='';csv+='PROFILE\nfirstName,lastName,email,phone,address,dob,social,clientType,recommendedBy,partnerFirst,partnerLast\n';csv+=[client.firstName,client.lastName,client.email,client.phone||'',client.address||'',client.dob||'',client.social||'',client.clientType||'',client.recommendedBy||'',client.partnerFirst||'',client.partnerLast||''].map(esc).join(',')+'\n';csv+='\nINCOME\nperson,label,gross,net,frequency\n';(client.incomeStreams||[]).forEach(s=>{csv+=[s.person,s.label,s.gross,s.net,s.freq].map(esc).join(',')+'\n';});csv+='\nBILLS\nname,assignedTo,cost,type,frequency,dueDay\n';(client.bills||[]).forEach(b=>{csv+=[b.name,b.assignedTo,b.cost,b.type,b.freq,b.dueDay||''].map(esc).join(',')+'\n';});csv+='\nDEBT\nname,balance,apr,minPayment,limit,hasPromo,promoBalance,promoRate,promoEndDate\n';(client.cards||[]).forEach(c=>{csv+=[c.name,c.balance,c.apr,c.min,c.limit,c.promo?'true':'false',c.promoBalance||0,c.promoRate||0,c.promoEnd||''].map(esc).join(',')+'\n';});csv+='\nASSETS\nchecking,savings,retirement,vehicle,realEstate\n';const a=client.assets||{};csv+=[a.checking,a.savings,a.retirement,a.vehicle,a.realEstate].map(esc).join(',')+'\n';csv+='\nLIABILITIES\ncreditCards,vehicleLoan,studentLoan,personalLoan\n';const l=client.liabilities||{};csv+=[l.creditCards,l.vehicle,l.student,l.personal].map(esc).join(',')+'\n';return csv;};
const dlCSV=(csv,name)=>{const blob=new Blob([csv],{type:"text/csv"});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download=name;a.click();URL.revokeObjectURL(url);};
const expCSV=client=>dlCSV(genCSV(client),`${client.firstName}_${client.lastName}_GA.csv`);
const dlTmpl=()=>{const t=`PROFILE\nfirstName,lastName,email,phone,address,dob,social,clientType,recommendedBy,partnerFirst,partnerLast\nJohn,Doe,john@email.com,(305) 555-0000,"123 Main St Miami FL",1990-01-01,123-45-6789,financeOnly,Referral,,\n\nINCOME\nperson,label,gross,net,frequency\np1,Main Job,5000,3800,biweekly\n\nBILLS\nname,assignedTo,cost,type,frequency,dueDay\nRent,joint,1800,regular,monthly2,1\n\nDEBT\nname,balance,apr,minPayment,limit,hasPromo,promoBalance,promoRate,promoEndDate\nChase Sapphire,5000,28.5,120,8000,false,0,0,\n\nASSETS\nchecking,savings,retirement,vehicle,realEstate\n2500,5000,8000,18000,0\n\nLIABILITIES\ncreditCards,vehicleLoan,studentLoan,personalLoan\n5000,14000,0,0\n`;dlCSV(t,"golden_anchor_template.csv");};
const parseCSV=(text,existing=null)=>{const lines=text.split('\n').map(l=>l.trim());let sec=null,hdr=null;const d={profile:null,income:[],bills:[],debt:[],assets:null,liabilities:null};for(const line of lines){if(!line)continue;const up=line.toUpperCase();if(['PROFILE','INCOME','BILLS','DEBT','ASSETS','LIABILITIES'].includes(up)){sec=up;hdr=null;continue;}if(!sec)continue;const vals=pLine(line);if(!hdr){hdr=vals;continue;}const obj={};hdr.forEach((h,i)=>obj[h.trim()]=(vals[i]||'').trim());if(sec==='PROFILE')d.profile=obj;else if(sec==='INCOME'&&obj.label)d.income.push(obj);else if(sec==='BILLS'&&obj.name)d.bills.push(obj);else if(sec==='DEBT'&&obj.name)d.debt.push(obj);else if(sec==='ASSETS')d.assets=obj;else if(sec==='LIABILITIES')d.liabilities=obj;}
const p=d.profile||{};return mig({...(existing||{}),firstName:p.firstName||'',lastName:p.lastName||'',email:p.email||'',phone:p.phone||'',address:p.address||'',dob:p.dob||'',social:p.social||'',clientType:p.clientType||'financeOnly',recommendedBy:p.recommendedBy||'',partnerFirst:p.partnerFirst||null,partnerLast:p.partnerLast||null,id:existing?.id||gid(),incomeStreams:d.income.map((s,i)=>({id:gid()+i,person:s.person||'p1',label:s.label,gross:+s.gross||0,net:+s.net||0,freq:s.frequency||s.freq||'monthly2'})),bills:d.bills.map((b,i)=>({id:gid()+i,name:b.name,assignedTo:b.assignedTo||'joint',cost:+b.cost||0,type:b.type||'regular',freq:b.frequency||b.freq||'monthly2',dueDay:+b.dueDay||1})),cards:d.debt.map((c,i)=>({id:gid()+i,name:c.name,balance:+c.balance||0,apr:+c.apr||0,min:+(c.minPayment||c.min)||0,limit:+c.limit||0,promo:c.hasPromo==='true',promoBalance:+c.promoBalance||0,promoRate:+c.promoRate||0,promoEnd:c.promoEndDate||''})),assets:d.assets?{checking:+d.assets.checking||0,savings:+d.assets.savings||0,retirement:+d.assets.retirement||0,vehicle:+d.assets.vehicle||0,realEstate:+d.assets.realEstate||0}:(existing?.assets||{checking:0,savings:0,retirement:0,vehicle:0,realEstate:0}),liabilities:d.liabilities?{creditCards:+d.liabilities.creditCards||0,vehicle:+(d.liabilities.vehicleLoan||0),student:+(d.liabilities.studentLoan||0),personal:+(d.liabilities.personalLoan||0)}:(existing?.liabilities||{creditCards:0,vehicle:0,student:0,personal:0})});};
function getClientRem(clients){const today=new Date();const day=today.getDate();const out=[];clients.forEach(c=>{(c.bills||[]).forEach(b=>{if(b.type!=="annual"&&b.dueDay){const diff=b.dueDay>=day?b.dueDay-day:b.dueDay+(31-day);if(diff<=7)out.push({clientName:`${c.firstName} ${c.lastName}`,clientId:c.id,name:b.name,dueDay:b.dueDay,amount:toM(b.cost,b.freq||"monthly2"),type:"bill",task:"Bill Due",daysUntil:diff});}});(c.cards||[]).forEach(cc=>{if(cc.min>0)out.push({clientName:`${c.firstName} ${c.lastName}`,clientId:c.id,name:cc.name,dueDay:null,amount:cc.min,type:"card",task:"Card Min",daysUntil:null});});});return out;}
function getAdvRem(clients,settings){const today=new Date();const out=[];clients.forEach(c=>{const snaps=c.monthSnapshots||[];if(settings.reminderAdvisor?.noContact){const last=snaps[snaps.length-1];const days=last?.savedAt?Math.floor((today-new Date(last.savedAt))/86400000):(snaps.length===0?999:0);if(days>=(settings.noContactDays||30))out.push({type:"noContact",priority:days>60?"high":"med",clientName:`${c.firstName} ${c.lastName}`,detail:`Last review ${days===999?"never":`${days} days ago`}`,task:"No Contact"});}if(settings.reminderAdvisor?.highDebt){const net=sumN(c.incomeStreams);const dsr=net>0?sumMin(c.cards)/net:0;if(dsr>0.36)out.push({type:"highDebt",priority:dsr>0.5?"high":"med",clientName:`${c.firstName} ${c.lastName}`,detail:`DSR ${(dsr*100).toFixed(0)}%`,task:"High DSR"});}if(settings.reminderAdvisor?.promoExpiring){(c.cards||[]).forEach(card=>{if(card.promo&&card.promoEnd){const dLeft=Math.floor((new Date(card.promoEnd)-today)/86400000);if(dLeft>=0&&dLeft<=60)out.push({type:"promo",priority:dLeft<=14?"high":"med",clientName:`${c.firstName} ${c.lastName}`,detail:`${card.name} ${dLeft} days`,task:"Promo Expiring"});}});}if(settings.reminderAdvisor?.debtIncreasing){if(snaps.length>=2&&snaps[snaps.length-1].debt>snaps[0].debt)out.push({type:"debtRising",priority:"med",clientName:`${c.firstName} ${c.lastName}`,detail:`+${fmt(snaps[snaps.length-1].debt-snaps[0].debt)}`,task:"Debt Rising"});}});return out;}
function Pill({children,color="#94A3B8"}){return<span style={{background:color+"22",color,border:`1px solid ${color}44`,borderRadius:99,padding:"1px 8px",fontSize:11,fontWeight:600,whiteSpace:"nowrap"}}>{children}</span>;}
