function Login({onLogin,t,isDark,onToggle}){const[em,setEm]=useState("");const[pw,setPw]=useState("");const[err,setErr]=useState("");const go=()=>{if(em===CREDS.email&&pw===CREDS.password)onLogin();else setErr("Invalid credentials.");};const INP={background:isDark?"#111827":"#F0F7FF",border:`1px solid ${isDark?"#4B5563":"#CBD5E1"}`,color:isDark?"#F1F5F9":"#0F172A",borderRadius:8,padding:"8px 12px",fontSize:13,outline:"none",width:"100%",boxSizing:"border-box"};return<div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:isDark?"linear-gradient(135deg,#0D1724,#1F2937)":"linear-gradient(135deg,#1C3557,#2A4A73)"}}><div style={{width:340}}><div style={{textAlign:"center",marginBottom:32}}><div style={{fontSize:40,marginBottom:8}}>A</div><div style={{fontSize:26,fontWeight:800,color:GOLD,letterSpacing:"0.06em",fontFamily:"Georgia,serif"}}>Golden Anchor</div><div style={{fontSize:10,color:"#94A3B8",letterSpacing:"0.2em",marginTop:2}}>FINANCIAL ADVISORY</div></div><div style={{background:isDark?"#1F2937":"#FFFFFF",border:`1px solid ${isDark?"#374151":"#CBD5E1"}`,borderRadius:16,padding:28,boxShadow:"0 32px 80px #0006"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><span style={{fontSize:12,fontWeight:600,color:"#6B7280"}}>{t.advisorPortal}</span><button onClick={onToggle} style={{fontSize:11,padding:"3px 10px",borderRadius:8,background:isDark?"#374151":"#EFF6FF",color:isDark?"#9CA3AF":"#1D4ED8",border:"none",cursor:"pointer"}}>{isDark?t.lightMode:t.darkMode}</button></div><div style={{marginBottom:14}}><label style={{fontSize:11,color:"#6B7280",display:"block",marginBottom:5}}>{t.email}</label><input value={em} onChange={ev=>setEm(ev.target.value)} style={INP} onKeyDown={ev=>ev.key==="Enter"&&go()}/></div><div style={{marginBottom:14}}><label style={{fontSize:11,color:"#6B7280",display:"block",marginBottom:5}}>{t.password}</label><input type="password" value={pw} onChange={ev=>setPw(ev.target.value)} style={INP} onKeyDown={ev=>ev.key==="Enter"&&go()}/></div>{err&&<div style={{fontSize:11,color:"#EF4444",marginBottom:12,padding:"8px 10px",background:"#EF444411",borderRadius:8}}>{err}</div>}<button onClick={go} style={{width:"100%",padding:12,borderRadius:12,fontWeight:800,fontSize:14,cursor:"pointer",background:`linear-gradient(135deg,${GOLD},#D4AF37)`,color:"#0D1B2A",border:"none",marginTop:4}}>{t.signIn}</button><div style={{marginTop:10,padding:"8px 10px",background:isDark?"#111827":"#F0F7FF",borderRadius:8,fontSize:10,color:"#6B7280"}}>mauricio@goldenanchor.life / GoldenAnchor2026</div></div></div></div>;}
export default function App(){const[loggedIn,setLoggedIn]=useState(false);const[lang,setLang]=useState("en");const[isDark,setDark]=useState(true);const[settings,setSettings]=useState(()=>{try{return{...DEF_SETTINGS,...JSON.parse(localStorage.getItem("ga_settings")||"{}")};} catch{return DEF_SETTINGS;}});const theme=isDark?makeDark(settings.darkAccent||GOLD):makeLight(settings.lightAccent||"#2563EB");const t=T[lang];const[nav,setNav]=useState("dashboard");const[selected,setSelected]=useState(null);const[selectedTab,setSelectedTab]=useState("report");const[addOpen,setAddOpen]=useState(false);const[profileOpen,setProfileOpen]=useState(false);const[clients,setClients]=useState(()=>{try{const s=localStorage.getItem("ga_v3");return s?JSON.parse(s).map(mig):SEED.map(mig);}catch{return SEED.map(mig);}});useEffect(()=>{try{localStorage.setItem("ga_v3",JSON.stringify(clients));}catch{}},[clients]);useEffect(()=>{try{localStorage.setItem("ga_settings",JSON.stringify(settings));}catch{}},[settings]);const upClient=useCallback(c=>{const mc=mig(c);setClients(p=>p.map(x=>x.id===mc.id?mc:x));setSelected(mc);},[]);const addClient=newC=>{const mc=mig(newC);setClients(p=>[...p,mc]);setAddOpen(false);setSelectedTab("intake");setSelected(mc);setNav("clients");};const importFromDash=e=>{const f=e.target.files[0];if(!f)return;const reader=new FileReader();reader.onload=ev=>{try{const nc=parseCSV(ev.target.result);setClients(p=>[...p,nc]);alert(`Imported: ${nc.firstName} ${nc.lastName}`);}catch{alert("Invalid CSV.");}};reader.readAsText(f);e.target.value="";};const NAV=[{id:"dashboard",l:t.dashboard},{id:"clients",l:t.clients},{id:"forms",l:t.forms},{id:"resources",l:t.resources},{id:"about",l:t.about}];if(!loggedIn)return<ThemeCtx.Provider value={theme}><Login onLogin={()=>setLoggedIn(true)} t={t} isDark={isDark} onToggle={()=>setDark(d=>!d)}/></ThemeCtx.Provider>;return<ThemeCtx.Provider value={theme}>{addOpen&&<NewClientModal onSave={addClient} onClose={()=>setAddOpen(false)} t={t}/>}{profileOpen&&<ProfileModal settings={settings} onSave={s=>{setSettings(s);setProfileOpen(false);}} onClose={()=>setProfileOpen(false)} t={t}/>}<div style={{display:"flex",minHeight:"100vh",background:theme.bg,fontFamily:"system-ui,sans-serif",color:theme.text,zoom:settings.zoom||1}}><div style={{width:210,flexShrink:0,background:theme.nav,borderRight:`1px solid ${theme.navBorder}`,display:"flex",flexDirection:"column"}}><div style={{padding:"18px 16px",borderBottom:`1px solid ${theme.navBorder}`}}><div style={{fontSize:17,fontWeight:800,color:GOLD,fontFamily:"Georgia,serif",letterSpacing:"0.04em"}}>Golden Anchor</div><div style={{fontSize:9,color:theme.sideMuted,letterSpacing:"0.14em",marginTop:2}}>ADVISOR PORTAL</div></div><nav style={{flex:1,padding:10}}>{NAV.map(n=><button key={n.id} onClick={()=>{setNav(n.id);setSelected(null);}} style={{width:"100%",display:"flex",alignItems:"center",gap:10,padding:"8px 12px",borderRadius:9,background:nav===n.id&&!selected?GOLD+"22":"transparent",color:nav===n.id&&!selected?GOLD:theme.sideMuted,fontWeight:600,border:"none",cursor:"pointer",fontSize:13,textAlign:"left",marginBottom:2}}>{n.l}</button>)}</nav><div style={{padding:10,borderTop:`1px solid ${theme.navBorder}`}}><button onClick={()=>setProfileOpen(true)} style={{width:"100%",padding:"7px",borderRadius:8,fontSize:12,cursor:"pointer",background:GOLD+"22",color:GOLD,border:`1px solid ${GOLD}44`,fontWeight:700,marginBottom:8}}>Settings</button><button onClick={()=>setDark(d=>!d)} style={{width:"100%",padding:"6px",borderRadius:8,fontSize:12,cursor:"pointer",background:"transparent",color:theme.sideMuted,border:`1px solid ${theme.navBorder}`,fontWeight:600,marginBottom:6}}>{isDark?t.lightMode:t.darkMode}</button><button onClick={()=>setLang(l=>l==="en"?"es":"en")} style={{width:"100%",padding:"5px",borderRadius:8,fontSize:12,cursor:"pointer",background:"transparent",color:theme.sideMuted,border:`1px solid ${theme.navBorder}`,fontWeight:700,marginBottom:10}}>EN / ES</button><div style={{fontSize:11,color:theme.sideMuted}}>{settings.advisorName||"Mauricio"}</div></div></div><div style={{flex:1,overflow:"hidden",display:"flex",flexDirection:"column"}}><div style={{flex:1,overflowY:"auto"}}>{selected?<ClientDetail client={selected} onUpdate={upClient} lang={lang} t={t} onBack={()=>setSelected(null)} startTab={selectedTab}/>:nav==="dashboard"?<Dashboard clients={clients} t={t} settings={settings} onSelect={c=>{setSelectedTab("report");setSelected(c);setNav("clients");}} onAdd={()=>setAddOpen(true)} onImport={importFromDash}/>:nav==="clients"?<ClientList clients={clients} t={t} onSelect={c=>{setSelectedTab("report");setSelected(c);}} onAdd={()=>setAddOpen(true)}/>:nav==="forms"?<FormsPage t={t}/>:nav==="resources"?<ResourcesPage t={t}/>:<AboutPage t={t} settings={settings}/>}</div></div></div></ThemeCtx.Provider>;}
